class Solution:
    def advantageCount(self, nums1, nums2):
        n = len(nums1)
        s1 = sorted(nums1)
        order = sorted(range(n), key=lambda i: -nums2[i])
        lo, hi = 0, n - 1
        ans = [None] * n
        for idx in order:
            if s1[hi] > nums2[idx]:
                ans[idx] = s1[hi]
                hi -= 1
            else:
                ans[idx] = s1[lo]
                lo += 1
        return ans

